for name, C in controllers.items():
    L = C * G;
    gm, pm, wg, wp = ctrl.margin(L);
    print(f'{name}: GM={gm:.2f} dB, PM={pm:.1f}deg, wg={wg:.2f}, wp={wp:.2f}')
    cl = ctrl.feedback(L); poles = ctrl.pole(cl); stable = all(np.real(p) < 0 for p in poles);
    Kv = ctrl.dcgain(ctrl.tf(C.num[0][0], C.den[0][0]) * ctrl.tf([4],[1,5,4,1])) if name in ['A','C'] else 0;
    ess = 0 if 'B' in name or 'D' in name else 1/Kv if Kv > 0 else float('inf');
    print(f'   Stable={stable}, ess_ramp={ess:.3f}')

