import numpy as np; from scipy.optimize import fsolve;
# L(s) = 50(s+5) / [s(s+2)(s+10)]
def L_mag(w):
    return 50*np.sqrt(w**2+25) / (w*np.sqrt(w**2+4)*np.sqrt(w**2+100))
def L_phase(w):
    return np.arctan2(w,5)*180/np.pi - 90 - np.arctan2(w,2)*180/np.pi - np.arctan2(w,10)*180/np.pi
# Find wgc
from scipy.optimize import brentq;
wgc = brentq(lambda w: L_mag(w)-1, 0.1, 20);
print(f'wgc={wgc:.2f}, PM={180+L_phase(wgc):.2f}')
# Phase approaches -180 from above
for w in [1,10,100,1000]:
    print(f'w={w}, phase={L_phase(w):.2f}, mag={L_mag(w):.4f}')

